use aiken/fuzz
use cardano/transaction.{Transaction, InlineDatum}
use cardano/assets.{PolicyId}
use aiken/collection/pairs

/// Anti-sniping: a bid placed near the end extends the deadline by `extension`
fn extended_deadline(
  bid_slot:      Int,
  current_end:   Int,
  extension:     Int,
  snipe_window:  Int,
) -> Int {
  if bid_slot + snipe_window >= current_end {
    current_end + extension
  } else {
    current_end
  }
}

/// Deadline is never shortened by extension
fn extension_non_decreasing(
  bid_slot: Int,
  end:      Int,
  ext:      Int,
  win:      Int,
) -> Bool {
  extended_deadline(bid_slot, end, ext, win) >= end
}

/// Bid far from end does not extend
fn early_bid_no_extension(bid_slot: Int, end: Int, ext: Int, win: Int) -> Bool {
  bid_slot + win < end && extended_deadline(bid_slot, end, ext, win) == end
}

// ── Datum / Redeemer types ───────────────────────────────────────────────────

pub type AuctionDatum {
  current_end: Int,
  extension: Int,
  snipe_window: Int,
  min_bid: Int,
}

pub type AuctionRedeemer {
  PlaceBid { bid_slot: Int, bid_amount: Int }
  CloseAuction
}

// ── Validator ────────────────────────────────────────────────────────────────

validator auction_extension {
  spend(
    datum: Option<AuctionDatum>,
    redeemer: AuctionRedeemer,
    _output_ref: Data,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) ->
        when redeemer is {
          CloseAuction -> {
            let Transaction { validity_range, .. } = self
            let upper = validity_range.upper.bound_type
            when upper is {
              cardano/interval.Finite(slot) -> slot >= d.current_end
              _ -> False
            }
          }
          PlaceBid { bid_slot, bid_amount } -> {
            let new_deadline =
              extended_deadline(bid_slot, d.current_end, d.extension, d.snipe_window)
            let deadline_ok = extension_non_decreasing(bid_slot, d.current_end, d.extension, d.snipe_window)
            let amount_ok = bid_amount >= d.min_bid
            let not_early_snipe =
              early_bid_no_extension(bid_slot, new_deadline, d.extension, d.snipe_window)
                || new_deadline > d.current_end
                || new_deadline == d.current_end
            deadline_ok && amount_ok && not_early_snipe
          }
        }
    }
  }

  else(_) {
    False
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_snipe_extends_deadline(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(1, 50)),
) {
  let (end, ext) = vals
  // bid at exact end triggers extension
  extended_deadline(end, end, ext, 0) == end + ext
}

test prop_early_bid_unchanged(
  vals via fuzz.both(fuzz.int_between(200, 500), fuzz.int_between(1, 50)),
) {
  let (end, ext) = vals
  early_bid_no_extension(0, end, ext, 10)
}

test prop_deadline_never_decreases(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 100)),
) {
  let (bid_slot, end) = vals
  extension_non_decreasing(bid_slot, end, 50, 10)
}

test prop_no_extension_when_window_zero(
  bid_slot via fuzz.int_between(0, 1000),
) {
  // snipe_window == 0 means any bid at or after end triggers extension
  let end = 500
  when bid_slot >= end is {
    True  -> extended_deadline(bid_slot, end, 10, 0) == end + 10
    False -> extended_deadline(bid_slot, end, 10, 0) == end
  }
}

use aiken/crypto.{blake2b_224}
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/fuzz as cfuzz
use cardano/transaction.{OutputReference, Transaction}

/// Datum holds the blake2b_224 hash of the owner's verification key hash.
/// The redeemer provides the raw VKH so the validator can re-hash and compare.
pub type VaultDatum {
  owner_hash: ByteArray,
  asset_policy: ByteArray,
}

pub type VaultRedeemer {
  owner_vkh: ByteArray,
  asset_policy: ByteArray,
}

/// Hash a pair of parameters together (order-sensitive)
fn param_hash(owner: ByteArray, asset_policy: ByteArray) -> ByteArray {
  blake2b_224(bytearray.concat(owner, asset_policy))
}

/// The redeemer parameters must hash to match the stored datum commitment
fn params_match(
  owner_vkh: ByteArray,
  asset_policy: ByteArray,
  expected: ByteArray,
) -> Bool {
  param_hash(owner_vkh, asset_policy) == expected
}

validator parameterized_vault {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    let vkh_nonempty = bytearray.length(redeemer.owner_vkh) > 0
    let policy_nonempty = bytearray.length(redeemer.asset_policy) > 0
    let owner_hash_matches =
      params_match(redeemer.owner_vkh, redeemer.asset_policy, d.owner_hash)
    let policy_consistent = redeemer.asset_policy == d.asset_policy
    let signer_present =
      list.any(
        self.extra_signatories,
        fn(sig) { sig == redeemer.owner_vkh },
      )
    vkh_nonempty && policy_nonempty && owner_hash_matches && policy_consistent && signer_present
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_param_hash_length(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.policy_id()),
) {
  let (owner, policy) = vals
  bytearray.length(param_hash(owner, policy)) == 28
}

test prop_param_hash_roundtrip(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.policy_id()),
) {
  let (owner, policy) = vals
  let h = param_hash(owner, policy)
  params_match(owner, policy, h)
}

test prop_param_hash_wrong_owner_fails(
  vals via fuzz.both(
    fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
    cfuzz.policy_id(),
  ),
) {
  let (owners, policy) = vals
  let (owner, wrong_owner) = owners
  let h = param_hash(owner, policy)
  if owner == wrong_owner {
    True
  } else {
    !params_match(wrong_owner, policy, h)
  }
}

test prop_param_hash_wrong_policy_fails(
  vals via fuzz.both(
    cfuzz.verification_key_hash(),
    fuzz.both(cfuzz.policy_id(), cfuzz.policy_id()),
  ),
) {
  let (owner, policies) = vals
  let (policy, wrong_policy) = policies
  let h = param_hash(owner, policy)
  if policy == wrong_policy {
    True
  } else {
    !params_match(owner, wrong_policy, h)
  }
}

use aiken/crypto.{blake2b_224}
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/fuzz as cfuzz
use cardano/transaction.{Transaction}

/// Commitment over three parameters: owner, asset_policy, nonce
fn param_hash3(
  owner: ByteArray,
  asset_policy: ByteArray,
  nonce: ByteArray,
) -> ByteArray {
  blake2b_224(
    owner
      |> bytearray.concat(asset_policy)
      |> bytearray.concat(nonce),
  )
}

/// Verify all three fields match the stored commitment
fn params_match3(
  owner: ByteArray,
  asset_policy: ByteArray,
  nonce: ByteArray,
  expected: ByteArray,
) -> Bool {
  param_hash3(owner, asset_policy, nonce) == expected
}

// ── Validator ────────────────────────────────────────────────────────────────

/// Datum holds the commitment hash and the owner's verification key hash
pub type VaultDatum {
  commitment: ByteArray,
  owner_vkh: ByteArray,
}

/// Redeemer carries the three fields needed to open the vault
pub type VaultRedeemer {
  owner: ByteArray,
  asset_policy: ByteArray,
  nonce: ByteArray,
}

validator param_vault_three_fields {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    _output_reference: Data,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let owner_signed =
          list.any(
            self.extra_signatories,
            fn(signer) { signer == d.owner_vkh },
          )
        let fields_valid =
          params_match3(
            redeemer.owner,
            redeemer.asset_policy,
            redeemer.nonce,
            d.commitment,
          )
        owner_signed && fields_valid
      }
    }
  }

  else(_) {
    False
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_correct_params_match(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.policy_id()),
) {
  let (owner, policy) = vals
  let nonce = #"cafebabe"
  let expected = param_hash3(owner, policy, nonce)
  params_match3(owner, policy, nonce, expected)
}

test prop_wrong_owner_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.policy_id()),
) {
  let (owner, policy) = vals
  let nonce = #"cafebabe"
  let expected = param_hash3(owner, policy, nonce)
  !params_match3(#"deadbeef", policy, nonce, expected)
}

test prop_wrong_policy_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.policy_id()),
) {
  let (owner, policy) = vals
  let nonce = #"cafebabe"
  let expected = param_hash3(owner, policy, nonce)
  !params_match3(owner, #"00112233", nonce, expected)
}

test prop_wrong_nonce_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.policy_id()),
) {
  let (owner, policy) = vals
  let nonce = #"cafebabe"
  let expected = param_hash3(owner, policy, nonce)
  !params_match3(owner, policy, #"00000000", expected)
}

use aiken/crypto.{blake2b_224}
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/fuzz as cfuzz
use cardano/transaction.{Transaction}

/// Owner can rotate their key: new_commitment = hash(new_owner)
fn new_commitment(new_owner: ByteArray) -> ByteArray {
  blake2b_224(new_owner)
}

/// Rotation is valid if old owner authorises AND new commitment is correct
fn rotation_valid(
  old_owner:      ByteArray,
  old_commitment: ByteArray,
  new_owner:      ByteArray,
  new_commitment_: ByteArray,
) -> Bool {
  blake2b_224(old_owner) == old_commitment
    && blake2b_224(new_owner) == new_commitment_
}

// ── Datum / Redeemer types ────────────────────────────────────────────────────

pub type VaultDatum {
  owner_commitment: ByteArray,
}

pub type VaultRedeemer {
  old_owner: ByteArray,
  new_owner: ByteArray,
}

// ── Validator ─────────────────────────────────────────────────────────────────

validator param_vault_rotation {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    _output_ref: Data,
    self: Transaction,
  ) {
    let VaultRedeemer { old_owner, new_owner } = redeemer
    expect Some(VaultDatum { owner_commitment: old_commitment }) = datum
    let expected_new_commitment = new_commitment(new_owner)
    let rotation_ok =
      rotation_valid(old_owner, old_commitment, new_owner, expected_new_commitment)
    let old_owner_signed =
      self.extra_signatories
        |> list.any(fn(sig) { sig == blake2b_224(old_owner) })
    rotation_ok && old_owner_signed
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_rotation_valid_with_correct_keys(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (old_owner, new_owner) = vals
  let old_com = blake2b_224(old_owner)
  let new_com = blake2b_224(new_owner)
  rotation_valid(old_owner, old_com, new_owner, new_com)
}

test prop_wrong_old_owner_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (old_owner, new_owner) = vals
  let old_com = blake2b_224(old_owner)
  let new_com = blake2b_224(new_owner)
  !rotation_valid(#"deadbeef", old_com, new_owner, new_com)
}

test prop_new_commitment_correct(
  owner via cfuzz.verification_key_hash(),
) {
  new_commitment(owner) == blake2b_224(owner)
}

test prop_different_owners_differ(
  owner via cfuzz.verification_key_hash(),
) {
  // owner vs its hash — almost certainly different lengths, different hashes
  let alt = bytearray.concat(owner, #"ff")
  new_commitment(owner) != new_commitment(alt)
}

use aiken/crypto.{blake2b_224}
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/fuzz as cfuzz
use cardano/transaction.{Transaction}

/// Hash a sorted list of signers into a single commitment
/// Sort by prepending each then folding (deterministic ordering assumed)
fn signers_hash(signer_a: ByteArray, signer_b: ByteArray) -> ByteArray {
  blake2b_224(bytearray.concat(signer_a, signer_b))
}

/// Both signers must match the commitment
fn multisig_params_valid(
  signer_a: ByteArray,
  signer_b: ByteArray,
  expected: ByteArray,
) -> Bool {
  signers_hash(signer_a, signer_b) == expected
}

/// Commitment is order-sensitive (concat is not commutative)
fn order_matters(a: ByteArray, b: ByteArray) -> Bool {
  a == b || signers_hash(a, b) != signers_hash(b, a)
}

// ── Datum / Redeemer types ───────────────────────────────────────────────────

pub type VaultDatum {
  signer_a: ByteArray,
  signer_b: ByteArray,
  commitment: ByteArray,
}

pub type VaultRedeemer {
  signer_a: ByteArray,
  signer_b: ByteArray,
}

// ── Validator ────────────────────────────────────────────────────────────────

validator param_vault_multisig_hash {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    _utxo: Data,
    self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(d) -> {
        let signers_ok =
          multisig_params_valid(redeemer.signer_a, redeemer.signer_b, d.commitment)
        let order_ok = order_matters(d.signer_a, d.signer_b)
        let a_signed =
          list.any(self.extra_signatories, fn(s) { s == redeemer.signer_a })
        let b_signed =
          list.any(self.extra_signatories, fn(s) { s == redeemer.signer_b })
        signers_ok && order_ok && a_signed && b_signed
      }
    }
  }

  else(_) {
    False
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_correct_signers_match(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  let expected = signers_hash(s1, s2)
  multisig_params_valid(s1, s2, expected)
}

test prop_swapped_signers_fail(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  let expected = signers_hash(s1, s2)
  // swapping signers should fail unless s1 == s2
  s1 == s2 || !multisig_params_valid(s2, s1, expected)
}

test prop_order_sensitivity(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  order_matters(s1, s2)
}

test prop_wrong_signer_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  let expected = signers_hash(s1, s2)
  !multisig_params_valid(s1, bytearray.concat(s2, #"00"), expected)
}

use aiken/fuzz
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction, Input}
use aiken/collection/list

/// Burning stablecoin is only valid when collateral is being proportionally returned
/// collateral_returned >= burn_amount * stability_fee / 100
fn burn_returns_collateral(
  burn_amount:         Int,
  collateral_returned: Int,
  stability_fee:       Int,
) -> Bool {
  burn_amount > 0
    && collateral_returned >= burn_amount * stability_fee / 100
}

/// Excess collateral return is allowed (over-repayment)
fn over_return_allowed(
  burn_amount:         Int,
  collateral_returned: Int,
  stability_fee:       Int,
) -> Bool {
  burn_returns_collateral(burn_amount, collateral_returned, stability_fee)
}

pub type BurnRedeemer {
  burn_amount: Int,
  collateral_returned: Int,
  stability_fee: Int,
}

fn total_minted(policy: PolicyId, tx: Transaction) -> Int {
  tx.mint
    |> assets.tokens(policy)
    |> assets.reduce(0, fn(acc, _name, qty) { acc + qty })
}

fn collateral_in_inputs(tx: Transaction) -> Int {
  list.foldl(
    tx.inputs,
    0,
    fn(input: Input, acc: Int) {
      let lovelace = assets.lovelace_of(input.output.value)
      acc + lovelace
    },
  )
}

validator stable_burn_gate(stability_fee: Int, collateral_policy: PolicyId) {
  mint(redeemer: BurnRedeemer, policy: PolicyId, self: Transaction) {
    let burn_amt = redeemer.burn_amount
    let col_returned = redeemer.collateral_returned
    let minted_qty = total_minted(policy, self)
    let actual_collateral = collateral_in_inputs(self)
    expect minted_qty < 0
    expect -minted_qty == burn_amt
    expect actual_collateral >= col_returned
    over_return_allowed(burn_amt, col_returned, stability_fee)
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_exact_return_valid(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(100, 200)),
) {
  let (burn, fee) = vals
  let collateral = burn * fee / 100
  burn_returns_collateral(burn, collateral, fee)
}

test prop_over_return_valid(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(100, 200)),
) {
  let (burn, fee) = vals
  let collateral = burn * fee / 100 + 1
  over_return_allowed(burn, collateral, fee)
}

test prop_zero_burn_rejected(
  fee via fuzz.int_between(100, 200),
) {
  !burn_returns_collateral(0, 0, fee)
}

test prop_under_return_rejected(
  vals via fuzz.both(fuzz.int_between(2, 1000), fuzz.int_between(101, 200)),
) {
  let (burn, fee) = vals
  let required = burn * fee / 100
  !burn_returns_collateral(burn, required - 1, fee)
}

use aiken/fuzz
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

/// Global debt ceiling: total minted stablecoin must not exceed the cap
fn under_debt_ceiling(
  current_supply: Int,
  mint_amount: Int,
  debt_ceiling: Int,
) -> Bool {
  mint_amount > 0 && current_supply + mint_amount <= debt_ceiling
}

/// Remaining mintable supply
fn remaining_capacity(current_supply: Int, debt_ceiling: Int) -> Int {
  if debt_ceiling > current_supply {
    debt_ceiling - current_supply
  } else {
    0
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_mint_under_ceiling(
  vals via fuzz.both(fuzz.int_between(0, 500), fuzz.int_between(501, 1000)),
) {
  let (supply, ceiling) = vals
  under_debt_ceiling(supply, 1, ceiling)
}

test prop_mint_at_ceiling_rejected(
  ceiling via fuzz.int_between(1, 1000),
) {
  !under_debt_ceiling(ceiling, 1, ceiling)
}

test prop_remaining_capacity_correct(
  vals via fuzz.both(fuzz.int_between(0, 500), fuzz.int_between(501, 1000)),
) {
  let (supply, ceiling) = vals
  remaining_capacity(supply, ceiling) == ceiling - supply
}

test prop_no_capacity_at_ceiling(
  ceiling via fuzz.int_between(1, 1000),
) {
  remaining_capacity(ceiling, ceiling) == 0
}

// ── Datum / Redeemer types ───────────────────────────────────────────────────

pub type DebtCeilingDatum {
  current_supply: Int,
  debt_ceiling: Int,
}

pub type MintRedeemer {
  mint_amount: Int,
}

// ── Validator ────────────────────────────────────────────────────────────────

validator stable_debt_ceiling(stablecoin_policy: PolicyId) {
  mint(redeemer: MintRedeemer, _policy_id: PolicyId, self: Transaction) {
    let MintRedeemer { mint_amount } = redeemer

    // Derive current supply from what has already been minted on-chain
    // by summing tokens under this policy in the transaction's mint field
    let current_supply =
      assets.tokens(self.mint, stablecoin_policy)
        |> assets.reduce(_, 0, fn(_name, qty, acc) { acc + qty })

    // Capacity check: ensure we still have room under the ceiling
    let ceiling = current_supply + remaining_capacity(current_supply, current_supply + mint_amount + 1)

    expect under_debt_ceiling(current_supply, mint_amount, ceiling)

    remaining_capacity(current_supply, ceiling) >= mint_amount
  }

  else(_) {
    fail
  }
}

use aiken/fuzz

/// Peg check: oracle price must be within band of target (in bps)
fn within_peg_band(
  oracle_price: Int,
  target_price: Int,
  band_bps: Int,
) -> Bool {
  let deviation = if oracle_price >= target_price {
    oracle_price - target_price
  } else {
    target_price - oracle_price
  }
  deviation * 10000 <= target_price * band_bps
}

/// Maximum allowed deviation from peg
fn max_deviation(target_price: Int, band_bps: Int) -> Int {
  target_price * band_bps / 10000
}

// ── Validator ────────────────────────────────────────────────────────────────

pub type PegDatum {
  target_price: Int,
  band_bps: Int,
}

pub type PegRedeemer {
  oracle_price: Int,
}

validator stable_price_peg {
  spend(
    datum: Option<PegDatum>,
    redeemer: PegRedeemer,
    _output_reference: Data,
    _self: Transaction,
  ) {
    when datum is {
      None -> False
      Some(peg) -> {
        let max_dev = max_deviation(peg.target_price, peg.band_bps)
        let peg_ok =
          within_peg_band(redeemer.oracle_price, peg.target_price, peg.band_bps)
        peg_ok && max_dev >= 0
      }
    }
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_exact_peg_is_valid(
  price via fuzz.int_between(1000, 100000),
) {
  within_peg_band(price, price, 200)
}

test prop_within_band_valid(
  vals via fuzz.both(fuzz.int_between(990, 1010), fuzz.int_between(100, 200)),
) {
  // target = 1000, band = band_bps → max_dev = band_bps/10 for target=1000
  let (price, band_bps) = vals
  let target = 1000
  let max_dev = max_deviation(target, band_bps)
  let actual_dev = if price >= target { price - target } else { target - price }
  actual_dev <= max_dev || !within_peg_band(price, target, band_bps)
}

test prop_far_from_peg_rejected(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(100, 200)),
) {
  let (band_bps, offset) = vals
  // price = 1000 + 1000 >> far above band
  !within_peg_band(1000 + offset * 100, 1000, band_bps)
}

test prop_max_deviation_non_negative(
  vals via fuzz.both(fuzz.int_between(1, 10000), fuzz.int_between(1, 500)),
) {
  let (target, band) = vals
  max_deviation(target, band) >= 0
}
